text:
Что выведет программа?
int a = 5;
int b = a++ + ++a;
cout << b;

Что выведет программа?
int arr[] = {10, 20, 30, 40, 50};
cout << *(arr + 3);

Что выведет данный код?
int x = 10;
int *p = &x;
*p = 20;
cout << x;

Определите результат выполнения кода:
int sum = 0;
for(int i = 1; i <= 5; i++)
    sum += i;
cout << sum;

Что выведет программа?
string s = "Hello";
cout << s.length();

Что выведет код?
int a = 15;
cout << (a % 4);

Что выведет данный фрагмент?
char c = 'A';
cout << (int)c;

Что выведет код?
int n = 5;
int factorial = 1;
for(int i = 1; i <= n; i++)
    factorial *= i;
cout << factorial;

Что выведет данный код?
bool a = true, b = false;
cout << (a && b) << " " << (a || b);

Что выведет программа?
int arr[3] = {1, 2, 3};
int *ptr = arr;
cout << ptr[1] + ptr[2];

Что выведет код?
int x = 7;
switch(x % 3) {
    case 0: cout << "A"; break;
    case 1: cout << "B"; break;
    case 2: cout << "C"; break;
}

Определите результат:
int a = 10, b = 3;
cout << fixed << setprecision(1) << (double)a/b;

Что выведет код?
int a[5] = {0};
a[2] = 7;
cout << a[0] << a[2] << a[4];

Определите результат выполнения:
int count = 0;
for(int i = 0; i < 10; i++)
    if(i % 2 == 0) count++;
cout << count;

Что выведет код?
string s = "Programming";
cout << s.substr(3, 4);

Определите результат:
int x = 1;
while(x < 64)
    x *= 2;
cout << x;

Что выведет данный код?
void swap(int &a, int &b) { int t = a; a = b; b = t; }
int main() {
    int x = 3, y = 7;
    swap(x, y);
    cout << x << " " << y;
}

Что выведет программа?
int arr[] = {5, 10, 15, 20};
int size = sizeof(arr) / sizeof(arr[0]);
cout << size;

Определите результат:
int f(int n) { if(n <= 1) return 1; return n * f(n-1); }
cout << f(4);

Что выведет данный код?
int a = 5, b = 10;
cout << (a > b ? a : b);
